class Bank:
    def __init__(self):
        self.konten = {}

    def erstelle_konto(self, konto_id, kontoinhaber, kontostand):
        self.konten[konto_id] = Konto(konto_id, kontoinhaber, kontostand)

    def autorisiertes_konto(self, konto_id, pin):
        # Hier müsste die Authentifizierung des Kontoinhabers erfolgen
        # Für das Beispiel nehmen wir an, dass der PIN immer korrekt ist
        return konto_id in self.konten and self.konten[konto_id].kontostand >= 0

    def auszahlung(self, konto_id, pin, betrag):
        if self.autorisiertes_konto(konto_id, pin):
            if self.konten[konto_id].kontostand >= betrag:
                self.konten[konto_id].kontostand -= betrag
                print(f"Auszahlung von {betrag} auf Konto {konto_id} erfolgreich.")
            else:
                print(f"Konto {konto_id} hat nicht ausreichend Guthaben für die Auszahlung von {betrag}.")
        else:
            print(f"Konto {konto_id} ist nicht autorisiert oder hat kein Guthaben.")

